                case "two" -> num.add(2);
                case "three" -> num.add(3);
                case "four" -> num.add(4);
                case "five" -> num.add(5);
                case "six" -> num.add(6);
                case "seven" -> num.add(7);
                case "eight" -> num.add(8);
                case "nine" -> num.add(9);
            }
        }
        Collections.sort(num);
        List<String> result = new ArrayList<>();
        for (int m : num) {
            switch (m) {
                case 0 -> result.add("zero");
